import{_ as t,o as a,c as i,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Custom Analytics Builder","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/custom-analytics.md","filePath":"analytics/custom-analytics.md"}'),r={name:"analytics/custom-analytics.md"};function s(l,e,n,c,u,d){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="custom-analytics-builder" tabindex="-1">Custom Analytics Builder <a class="header-anchor" href="#custom-analytics-builder" aria-label="Permalink to &quot;Custom Analytics Builder&quot;">​</a></h1><p>The <strong>Custom</strong> tab is a premium builder for making your own analytics view from the data already inside your scope.</p><p>For the general locked/active premium behavior, see <a href="./../subscriptions/premium-features.html">Premium Features</a>. This page focuses on the Custom tab itself.</p><h2 id="locked-state" tabindex="-1">Locked state <a class="header-anchor" href="#locked-state" aria-label="Permalink to &quot;Locked state&quot;">​</a></h2><p>Without the custom analytics premium feature, the tab shows a locked card and a subscription request button instead of data.</p><blockquote><p>Screenshot placeholder: <code>premium-custom-locked.png</code> (S53 locked view)</p></blockquote><p>The locked message says this feature can build custom tables and charts by:</p><ul><li>event</li><li>date range</li><li>metric</li><li>grouping</li></ul><h2 id="active-state" tabindex="-1">Active state <a class="header-anchor" href="#active-state" aria-label="Permalink to &quot;Active state&quot;">​</a></h2><p>The unlocked builder is present in the current frontend code and is working as a real builder, not just a placeholder.</p><blockquote><p>Screenshot placeholder: <code>premium-custom-active.png</code> (S53 active view)</p></blockquote><p>When active, the page shows:</p><ul><li>an <strong>All events</strong> filter</li><li><strong>from</strong> and <strong>to</strong> date filters</li><li>a metric selector with <strong>Total score</strong>, <strong>Average score</strong>, <strong>Participation rate</strong>, <strong>Row count</strong>, and <strong>Active count</strong></li><li>a grouping selector with <strong>event</strong>, <strong>date</strong>, <strong>player</strong>, <strong>alliance</strong>, <strong>category</strong>, and <strong>status</strong></li><li>a trend chart for the selected metric</li><li>a <strong>Top Groups</strong> card</li><li>a <strong>Custom Analytics Table</strong></li></ul><p>The results table includes:</p><ul><li>group name</li><li>the selected metric value</li><li>total score</li><li>average score</li><li>participation</li><li>row count</li><li>active count</li></ul><h2 id="what-this-tab-is-best-for" tabindex="-1">What this tab is best for <a class="header-anchor" href="#what-this-tab-is-best-for" aria-label="Permalink to &quot;What this tab is best for&quot;">​</a></h2><p>Use Custom analytics when the built-in tabs are close, but not quite the question you need answered. For example:</p><ul><li>compare one metric across event types</li><li>narrow analytics to a date range</li><li>group results by alliance, player, or status</li><li>look at participation instead of score totals</li></ul><h2 id="verification-note" tabindex="-1">Verification note <a class="header-anchor" href="#verification-note" aria-label="Permalink to &quot;Verification note&quot;">​</a></h2><p>This file is based on direct frontend code verification of the unlocked builder. No fallback wording was needed for the active state.</p><h2 id="related-guides" tabindex="-1">Related guides <a class="header-anchor" href="#related-guides" aria-label="Permalink to &quot;Related guides&quot;">​</a></h2><ul><li><a href="./overview.html">Analytics Overview</a></li><li><a href="./alliance.html">Alliance Analytics</a></li><li><a href="./../subscriptions/premium-features.html">Premium Features</a></li></ul>',22)])])}const m=t(r,[["render",s]]);export{p as __pageData,m as default};
